.load extensions/tls-cert/target/wasm32-wasip2/release/tls_cert_extension.component.wasm

/* tls-cert  X.509 v3 certificate parsing (RFC 5280).
 *
 * Fixture: a self-signed RSA-2048 cert generated for the smoke,
 *   subject  = CN=example.com, O=Example Inc, C=US
 *   issuer   = same (self-signed)
 *   serial   = 0be4349a5c650dbc0f37e628c0f343211cf82849
 *   sig      = sha256WithRSAEncryption
 *   notBefore= 2026-06-20T13:31:30Z
 *   notAfter = 2036-06-17T13:31:30Z
 *   SAN      = DNS:example.com, DNS:www.example.com,
 *              IP:127.0.0.1, email:ops@example.com
 *   SHA-256 fingerprint of DER:
 *     97d7a61b4f88cc9e3dd8bd7de1b3dbe2491221cd9f0f04adbd4f02f489c8f233
 *
 * The cert is reproduced as a hex literal so the smoke is
 * deterministic across runs. PEM input is exercised via
 * CAST(<pem-hex-blob> AS TEXT)  the smoke harness strips lines
 * starting with  (line-comment heuristic) so an inline
 * -----BEGIN CERTIFICATE----- literal would not survive the
 * preprocessor.
 */

CREATE TABLE fixtures(name TEXT PRIMARY KEY, der BLOB, pem TEXT);
INSERT INTO fixtures(name, der, pem) VALUES (
  'self',
  x'',
  CAST(x'' AS TEXT));
INSERT INTO fixtures(name, der, pem) VALUES ('random', x'deadbeefcafef00d', NULL);

/* Acceptance 1  every well-known field extracts from the DER fixture. */
SELECT cert_subject(der)              FROM fixtures WHERE name='self';
SELECT cert_issuer(der)               FROM fixtures WHERE name='self';
SELECT cert_serial(der)               FROM fixtures WHERE name='self';
SELECT cert_not_before(der)           FROM fixtures WHERE name='self';
SELECT cert_not_after(der)            FROM fixtures WHERE name='self';
SELECT cert_sig_algorithm(der)        FROM fixtures WHERE name='self';
SELECT cert_public_key_algorithm(der) FROM fixtures WHERE name='self';
SELECT cert_public_key_bits(der)      FROM fixtures WHERE name='self';

/* SHA-256 fingerprint, lowercase hex, no separators. Matches
 * `openssl x509 -fingerprint -sha256` byte-for-byte (with colons
 * stripped + lowercased). */
SELECT cert_fingerprint_sha256(der)   FROM fixtures WHERE name='self';

/* SANs as JSON array  DNS / IP / email entries. */
SELECT cert_sans(der)                 FROM fixtures WHERE name='self';

/* self-signed: subject == issuer  1. */
SELECT cert_self_signed(der)          FROM fixtures WHERE name='self';

/* cert_is_valid_now with an explicit epoch (deterministic):
 *   2030-01-01T00:00:00Z = 1893456000  inside the validity range  1
 *   1980-01-01T00:00:00Z = 315532800   before notBefore           0
 *   2050-01-01T00:00:00Z = 2524608000  after notAfter             0
 */
SELECT cert_is_valid_now(der, 1893456000) FROM fixtures WHERE name='self';
SELECT cert_is_valid_now(der, 315532800)  FROM fixtures WHERE name='self';
SELECT cert_is_valid_now(der, 2524608000) FROM fixtures WHERE name='self';

/* cert_all returns valid JSON; spot-check via json_extract. */
SELECT json_extract(cert_all(der), '$.subject')             FROM fixtures WHERE name='self';
SELECT json_extract(cert_all(der), '$.fingerprint_sha256')  FROM fixtures WHERE name='self';
SELECT json_extract(cert_all(der), '$.self_signed')         FROM fixtures WHERE name='self';
SELECT json_extract(cert_all(der), '$.public_key_bits')     FROM fixtures WHERE name='self';
SELECT json_array_length(json_extract(cert_all(der), '$.sans')) FROM fixtures WHERE name='self';

/* Acceptance 2  PEM accepted same as DER. Subject extracted
 * from the PEM-armored form must match the DER form. */
SELECT cert_subject(pem) = cert_subject(der) FROM fixtures WHERE name='self';
SELECT cert_fingerprint_sha256(pem) = cert_fingerprint_sha256(der) FROM fixtures WHERE name='self';

/* Acceptance 3  random bytes  every fn returns NULL (no panic). */
SELECT cert_subject(der)              FROM fixtures WHERE name='random';
SELECT cert_issuer(der)               FROM fixtures WHERE name='random';
SELECT cert_serial(der)               FROM fixtures WHERE name='random';
SELECT cert_fingerprint_sha256(der)   FROM fixtures WHERE name='random';
SELECT cert_all(der)                  FROM fixtures WHERE name='random';

/* NULL input  NULL. */
SELECT cert_subject(NULL);

/* tls_cert_version is non-empty. */
SELECT length(tls_cert_version()) > 0;
